#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=2005;
ll n,m,a[N][N],q1[N],q2[N],num,ans;
string s[N];
int main() 
{
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>s[i];
		s[i]=" "+s[i];
	}
	for(int i=n;i>0;i--)
	{
		for(int j=m;j>0;j--)
		{
			if(s[i][j]=='.') a[i][j]=a[i+1][j]+1;
		}
	}
	for(int i=1;i<=n;i++)
	{
		num=0;
		q2[0]=m+1;
		for(int j=m;j>0;j--)
		{
			if(s[i][j]=='#')
			{
				q2[num=0]=j;
				continue;
			}
			while(num&&q1[num]>=a[i][j]) num--;
			num++;
			q1[num]=a[i][j];
			q2[num]=j;
			for(int k=num;k>0;k--)
			{
				int tmp=q1[k];
				ans+=(tmp*(tmp+1)/2*((q2[k]+q2[k-1]-1)*(q2[k-1]-q2[k])/2-(q2[k-1]-q2[k])*(j-1)));
			}	
		}
	}
	cout<<ans;
	return 0;
}
